const root = $input.first().json;
const body = root.body ?? root;
const diff = body.diff ?? body.patch ?? body.text ?? '';
const file = body.file ?? body.path ?? '';
const meta = body.meta;
let review_text = typeof diff === 'string' ? diff : (diff != null ? JSON.stringify(diff) : '');
if (!review_text.trim()) review_text = 'No diff provided';
if (file) review_text += '\n\nFile: ' + String(file);
if (meta != null && meta !== '') {
  const metaStr = typeof meta === 'string' ? meta : JSON.stringify(meta);
  review_text += '\n\nMeta: ' + metaStr;
}
return [{ json: { review_text, file_hint: String(file || '') } }];

const item = $input.first().json;
const raw = item.choices?.[0]?.message?.content;
const err = (m) => ({ json: { ok: false, error: m, raw: typeof raw === 'string' ? raw.slice(0, 2000) : '' } });
if (raw == null || typeof raw !== 'string') return [err('missing_content')];
function tryParse(s) {
  try { return JSON.parse(s.trim()); } catch (e) { return null; }
}
let parsed = tryParse(raw);
if (parsed === null) {
  const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (fence) parsed = tryParse(fence[1]);
}
if (parsed === null) {
  const i = raw.indexOf('[');
  const j = raw.lastIndexOf(']');
  if (i >= 0 && j > i) parsed = tryParse(raw.slice(i, j + 1));
}
if (parsed === null) return [err('invalid_json')];
if (!Array.isArray(parsed)) return [err('not_array')];
for (let i = 0; i < parsed.length; i++) {
  const o = parsed[i];
  if (o === null || typeof o !== 'object') return [err('item_not_object')];
  if (!['low', 'medium', 'high'].includes(o.severity)) return [err('bad_severity')];
  if (typeof o.finding !== 'string') return [err('bad_finding')];
  if (o.file != null && typeof o.file !== 'string') return [err('bad_file')];
  if (o.fix != null && typeof o.fix !== 'string') return [err('bad_fix')];
}
return [{ json: { ok: true, findings: parsed } }];
